INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (10118, 8, 20063115, 5118061, 1, 0, 2834, "青空の下で謁見", "フリーマーケット会場", 40, 7, 91002, 2, "フリーマーケットを訪れたジータが出会ったのは\n城をこっそり抜け出していたペコリーヌだった。", "ペコリーヌとの出会い");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (10118, 8, 20063115, 5118062, 1, 0, 2835, "未来の騎空団\nマスコット？", "フリーマーケット会場", 40, 7, 91002, 2, "ジータたちがフリーマーケットを巡っていると\n露店を出していたマホに声をかけられる。", "マホとの出会い");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (10118, 8, 20063115, 5118063, 1, 0, 2837, "お嬢さまからの\n緊急依頼", "ランドソル市街地", 40, 7, 91002, 2, "ジータが騎空団への依頼を確認していると、\n高笑いをしながらアキノが現れる。", "アキノとの出会い");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (10118, 8, 20063115, 5118064, 1, 0, 4108402, "黄金色の悩みごと", "フリーマーケット会場", 40, 18, 91002, 2, "ジータたちは、フリーマーケット会場で\n少し困った様子のジュンを見かける。", "ジュンとの出会い");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (10118, 8, 20063115, 5118065, 1, 0, 4107402, "白熱！　格闘大会！", "フリーマーケット会場", 40, 18, 91002, 2, "フリーマーケットの隅で開かれる格闘大会──\nそこにはカオリもいて……？", "カオリとの出会い");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (10118, 8, 20063115, 5118066, 1, 1, 9000227, "祭り太鼓はオーエドの華", "オーエド町", 40, 16, 91002, 2, "太鼓祭を控えるオーエド町──\nジータは、困った様子のニノンと出会う。", "ニノンとの出会い");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (10118, 8, 20063115, 5118067, 1, 0, 2101181, "人気者は遅れて\nやってくる", "フリーマーケット会場", 40, 19, 91002, 3, "ビカラはイベントに出演中のスズナを見かける。\nしかし、スズナはどこか困っているようで……？", "スズナとの出会い");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (10118, 8, 20063115, 5118068, 1, 0, 4109402, "巫女・ミーツ・魔法少女", "ランドソル市街地", 40, 18, 91002, 3, "ビカラたちが街を散策していると、通りかかった\nナナカが興奮した様子で近づいてきて……？", "ナナカとの出会い");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (10118, 8, 20063115, 5118069, 1, 0, 4305402, "ネズ耳は二度なくなる", "フリーマーケット会場", 40, 18, 91002, 3, "ネズ耳をなくしてしまい絶望するビカラ。同じ頃\nキャルとコッコロは落とし物を拾っており……", "キャル＆コッコロとの出会い");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (10118, 8, 20063115, 5118070, 1, 0, 4101402, "この出会いにカンパイ！", "ランドソル市街地", 40, 18, 91002, 3, "街外れでひと休みをしていたビカラたちは、\nすっかりゴキゲンな様子のユカリと出会う。", "ユカリとの出会い");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (10118, 8, 20063115, 5118071, 1, 0, 4106402, "陰陽アンサンブル", "ランドソル市街地", 40, 18, 91002, 3, "ビカラは、人混みに怯えるアオイを心配し、\n陽気に声をかけるも……", "アオイとの出会い");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (10118, 8, 20063115, 5118072, 1, 1, 2836, "運試し十番勝負！", "フリーマーケット会場", 40, 7, 91002, 3, "ビカラがフリーマーケット会場を歩いていると\n占いをしていたシノブに声をかけられる。", "シノブとの出会い");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (10118, 0, 20063115, 5118600, 0, 0, 0, "彼女たちの新たな日常", 0, 0, 0, 0, 1, 0, "オープニング");
